using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    map<string, int> businessPriority = {
        {"electronics", 0},
        {"grocery", 1},
        {"pharmacy", 2},
        {"restaurant", 3}
    };

    vector<pair<string, string>> validCoupons;

    for (int i = 0; i < code.size(); ++i) {
        if (code[i].empty()) continue;
        string bl = businessLine[i];
        if (bl != "electronics" && bl != "grocery" && bl != "pharmacy" && bl != "restaurant") continue;
        if (!isActive[i]) continue;
        regex pattern("^[a-zA-Z0-9_]+$");
        if (regex_match(code[i], pattern)) {
            validCoupons.push_back({bl, code[i]});
        }
    }

    auto comp = [&](const pair<string, string>& a, const pair<string, string>& b) {
        int aPri = businessPriority[a.first];
        int bPri = businessPriority[b.first];
        if (aPri != bPri) return aPri < bPri;
        return a.second < b.second;
    };

    sort(validCoupons.begin(), validCoupons.end(), comp);

    vector<string> result;
    for (const auto& p : validCoupons) {
        result.push_back(p.second);
    }

    return result;
}
