#include <vector>
#include <string>
#include <regex>
#include <map>
#include <algorithm>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    map<string, int> businessOrder = {
        {"electronics", 0},
        {"grocery", 1},
        {"pharmacy", 2},
        {"restaurant", 3}
    };

    vector<pair<string, string>> validCoupons;

    for (size_t i = 0; i < code.size(); ++i) {
        // Check code validity
        if (code[i].empty()) continue;
        regex pattern("^[a-zA-Z0-9_]+$");
        if (!regex_match(code[i], pattern)) continue;

        // Check businessLine
        auto it = businessOrder.find(businessLine[i]);
        if (it == businessOrder.end()) continue;

        // Check isActive
        if (!isActive[i]) continue;

        // All conditions met
        validCoupons.emplace_back(businessLine[i], code[i]);
    }

    // Sort the valid coupons
    sort(validCoupons.begin(), validCoupons.end(), [&](const auto& a, const auto& b) {
        int orderA = businessOrder[a.first];
        int orderB = businessOrder[b.first];
        if (orderA != orderB) {
            return orderA < orderB;
        }
        return a.second < b.second;
    });

    // Extract the codes
    vector<string> result;
    for (const auto& p : validCoupons) {
        result.push_back(p.second);
    }

    return result;
}

